1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const INSURANCE_VALUES: Record<string, number> = {
12	  sword: 1000,
13	  amulet: 600,
14	  staff: 800,
15	  potion: 400,
16	  rune: 250,
17	  moonstone: 250,
18	};
19	
20	const DEDUCTIBLE = 100;
21	
22	const PROCESSING_FEE = 5;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	function basePremium(item: any): number {
34	  return BASE_PREMIUMS[item.type] ?? 0;
35	}
36	
37	const COMPONENT_TYPES = ["rune", "moonstone"];
38	const BLOCK_SIZE = 3;
39	const BLOCK_PREMIUM = 60;
40	
41	function isComponent(item: any): boolean {
42	  return COMPONENT_TYPES.includes(item.type);
43	}
44	
45	function groupByType(items: any[]): Record<string, any[]> {
46	  const result: Record<string, any[]> = {};
47	  for (const item of items) {
48	    if (!result[item.type]) result[item.type] = [];
49	    result[item.type].push(item);
50	  }
51	  return result;
52	}
53	
54	function componentGroupPremium(group: any[]): number {
55	  if (group.length === BLOCK_SIZE) return BLOCK_PREMIUM;
56	  return group.reduce((sum: number, item: any) => sum + basePremium(item), 0);
57	}
58	
59	export function claimOffice(input: any): unknown {
60	  const results = [];
61	  const quoteSteps: any[] = [];
62	  let quoteCount = 0;
63	  for (const step of input.steps) {
64	    if (step.op === "claim") {
65	      const policyItems = quoteSteps[step.policy];
66	      const insuranceSum = policyItems.reduce(
67	        (sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0),
68	        0
69	      );
70	      const cap = 2 * insuranceSum;
71	      let payout = 0;
72	      for (const damage of step.incident.damages) {
73	        payout += damage.amount - DEDUCTIBLE;
74	      }
75	      const remainingCap = cap - payout;
76	      results.push({ payout, remainingCap });
77	      continue;
78	    }
79	
80	    quoteSteps.push(step.items);
81	
82	    validateItemTypes(step.items);
83	
84	    const components = step.items.filter(isComponent);
85	    const nonComponents = step.items.filter((i: any) => !isComponent(i));
86	
87	    let rawPolicyBase = 0;
88	    let itemSpecificSurcharges = 0;
89	
90	    for (const item of nonComponents) {
91	      const base = basePremium(item);
92	      rawPolicyBase += base;
93	      if (item.cursed) {
94	        itemSpecificSurcharges += base * 0.5;
95	      }
96	      if (item.enchantment >= 5) {
97	        itemSpecificSurcharges += base * 0.3;
98	      }
99	    }
100	
101	    for (const group of Object.values(groupByType(components))) {
102	      rawPolicyBase += componentGroupPremium(group);
103	    }
104	
105	    let policyWideModifier = 0;
106	
107	    // First insurance surcharge: 10% of policy base premium (always applies)
108	    policyWideModifier += rawPolicyBase * 0.1;
109	
110	    if (input.customer.yearsWithMHPCO >= 2) {
111	      policyWideModifier -= rawPolicyBase * 0.2;
112	    }
113	
114	    quoteCount++;
115	    if (quoteCount > 1) {
116	      policyWideModifier -= rawPolicyBase * 0.15;
117	    }
118	
119	    const premium = Math.ceil(rawPolicyBase + itemSpecificSurcharges + policyWideModifier + PROCESSING_FEE);
120	
121	    results.push({ premium });
122	  }
123	  return { results };
124	}
